class UUIDGenerator {
  String generateV4() {
    final bytes = _generateSecureRandomBytes(16);
    
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;
    
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    
    return '${hex.substring(0, 8)}-${hex.substring(8, 12)}-${hex.substring(12, 16)}-${hex.substring(16, 20)}-${hex.substring(20, 32)}';
  }

  Uint8List _generateSecureRandomBytes(int length) {
    final secureRandom = Platform.isAndroid || Platform.isIOS || Platform.isLinux || Platform.isMacOS || Platform.isWindows
        ? _PlatformSecureRandom()
        : _FallbackSecureRandom();
    
    return secureRandom.nextBytes(length);
  }
}

abstract class SecureRandomSource {
  Uint8List nextBytes(int length);
}

class _PlatformSecureRandom implements SecureRandomSource {
  @override
  Uint8List nextBytes(int length) {
    final bytes = Uint8List(length);
    final random = Random.secure();
    
    for (int i = 0; i < length; i++) {
      bytes[i] = random.nextInt(256);
    }
    
    return bytes;
  }
}

class _FallbackSecureRandom implements SecureRandomSource {
  @override
  Uint8List nextBytes(int length) {
    final bytes = Uint8List(length);
    final random = Random.secure();
    
    for (int i = 0; i < length; i++) {
      bytes[i] = random.nextInt(256);
    }
    
    return bytes;
  }
